-- Unified Supabase catalog for all existing and imported puzzles.
ALTER TABLE public.edubite_content_questions
  DROP CONSTRAINT IF EXISTS edubite_content_questions_domain_check;

ALTER TABLE public.edubite_content_questions
  ADD CONSTRAINT edubite_content_questions_domain_check
  CHECK (domain IN ('dailydose', 'funbrain', 'puzzle'));

ALTER TABLE public.edubite_content_questions
  ADD COLUMN IF NOT EXISTS content_key text,
  ADD COLUMN IF NOT EXISTS metadata jsonb NOT NULL DEFAULT '{}'::jsonb;

CREATE UNIQUE INDEX IF NOT EXISTS idx_edubite_content_questions_puzzle_key
  ON public.edubite_content_questions (domain, content_key)
  WHERE domain = 'puzzle';

DROP POLICY IF EXISTS edubite_content_questions_select_published
  ON public.edubite_content_questions;
CREATE POLICY edubite_content_questions_select_published
  ON public.edubite_content_questions
  FOR SELECT
  TO anon, authenticated
  USING (
    (domain <> 'puzzle' AND published = true)
    OR public.edubite_is_content_admin()
  );

WITH source AS (
  SELECT *
  FROM jsonb_to_recordset($puzzles$[{"content_key":"three-switches","active_date":"2026-10-26","tag":"Logic","q":"Three switches outside a closed room control three bulbs inside. You may enter the room only once. How will you identify which switch controls each bulb?","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":"11","metadata":{"number":1,"title":"The Three Switches","grade":"XI","kind":"open-ended","hint":"Heat can carry information that light cannot.","answer":"Turn on switch 1 for several minutes, then turn it off. Turn on switch 2 and enter. The glowing bulb belongs to switch 2, the warm bulb to switch 1, and the cold bulb to switch 3."}},{"content_key":"wrong-labels","active_date":"2026-10-27","tag":"Logic","q":"Three boxes are labelled Apples, Oranges, and Apples & Oranges. Every label is wrong. You may pick one fruit from only one box. How can you correctly label all three boxes?","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":"11","metadata":{"number":2,"title":"The Wrong Labels","grade":"XI","kind":"open-ended","hint":"Start with the label that claims a mix — it cannot be a mix.","answer":"Pick from the box labelled Apples & Oranges. Since its label is wrong, it contains only one kind of fruit. Use that fruit to identify the box, then determine the remaining two by elimination."}},{"content_key":"average-speed-trap","active_date":"2026-10-28","tag":"Math","q":"A student travels from home to school at 30 km/h and returns along the same route at 60 km/h. What is the average speed for the entire journey?","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":"11","metadata":{"number":3,"title":"The Average-Speed Trap","grade":"XI","kind":"open-ended","hint":"Average speed is total distance ÷ total time — not the mean of the two speeds.","answer":"40 km/h, not 45 km/h."}},{"content_key":"missing-square","active_date":"2026-10-29","tag":"Geometry","q":"A square has side length 10 cm. Its four corners are cut off by identical right-angled triangles with legs of 2 cm each. What percentage of the original area remains?","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":"11","metadata":{"number":4,"title":"The Missing Square","grade":"XI","kind":"open-ended","hint":"Original area = 100 cm². Each triangle removes ½ × 2 × 2 = 2 cm².","answer":"Original area 100 cm². Four triangles remove 8 cm². Remaining area 92 cm², or 92%."}},{"content_key":"clock-overlap","active_date":"2026-10-30","tag":"Math","q":"Between 3:00 p.m. and 4:00 p.m., at what exact time will the hour hand and minute hand overlap?","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":"11","metadata":{"number":5,"title":"The Clock Puzzle","grade":"XI","kind":"open-ended","hint":"Hands overlap every 65 ⁵⁄₁₁ minutes; start counting from 3:00.","answer":"Approximately 3:16:21.8 p.m."}},{"content_key":"falling-objects","active_date":"2026-10-31","tag":"Physics","q":"A heavy ball and a light ball are dropped simultaneously from the same height in a vacuum. Which reaches the ground first? What happens if the heavy ball and light ball are tied together?","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":"11","metadata":{"number":6,"title":"The Falling Objects Puzzle","grade":"XI","kind":"open-ended","hint":"In a vacuum there is no air resistance — only gravity.","answer":"Both reach together in a vacuum. Tying them together does not make the combination fall faster; all objects have the same gravitational acceleration in a vacuum."}},{"content_key":"number-machine","active_date":"2026-11-01","tag":"Math","q":"Find the next number:\n\n2,  6,  12,  20,  30,  ?","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":"11","metadata":{"number":7,"title":"The Number Machine","grade":"XI","kind":"open-ended","hint":"Look at the gaps between consecutive terms.","answer":"42. The pattern is n(n + 1): 1×2=2, 2×3=6, 3×4=12, 4×5=20, 5×6=30, 6×7=42."}},{"content_key":"candle-puzzle","active_date":"2026-11-02","tag":"Math","q":"Two candles have equal lengths. One burns completely in four hours and the other in five hours. They are lit together. After how much time will one candle be exactly twice as long as the other?","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":"11","metadata":{"number":8,"title":"The Candle Puzzle","grade":"XI","kind":"open-ended","hint":"Set remaining lengths as functions of time and solve B = 2A.","answer":"After 10/3 hours (3 hours 20 minutes). At that moment the slower-burning candle is twice as long as the faster one."}},{"content_key":"infinite-hotel","active_date":"2026-11-03","tag":"Math","q":"A hotel has infinitely many rooms, and every room is occupied. One new guest arrives. Can the hotel accommodate the guest without asking anyone to leave?","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":"12","metadata":{"number":9,"title":"The Infinite Hotel","grade":"XII","kind":"open-ended","hint":"Infinity plus one is still infinity — but you may need to reshuffle.","answer":"Yes. Move the guest in room n to room n + 1 for every n. Room 1 becomes free for the new guest."}},{"content_key":"two-rope","active_date":"2026-11-04","tag":"Logic","q":"You have two ropes. Each rope takes exactly 60 minutes to burn, but neither burns at a uniform rate. How can you measure exactly 45 minutes?","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":"12","metadata":{"number":10,"title":"The Two-Rope Puzzle","grade":"XII","kind":"open-ended","hint":"Lighting both ends of a rope finishes it in half the time.","answer":"Light rope A at both ends and rope B at one end. Rope A finishes in 30 minutes. At that moment, light the second end of rope B. Its remaining portion takes 15 minutes. Total: 45 minutes."}},{"content_key":"probability-boys","active_date":"2026-11-05","tag":"Probability","q":"A family has two children. You are told that at least one child is a boy. What is the probability that both children are boys?","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":"12","metadata":{"number":11,"title":"The Probability Puzzle","grade":"XII","kind":"open-ended","hint":"List equally likely ordered outcomes: BB, BG, GB, GG.","answer":"Assuming boys and girls are equally likely and birth order matters, the possibilities given at least one boy are BB, BG, GB. Therefore the probability both are boys is 1/3."}},{"content_key":"calculus-limit","active_date":"2026-11-06","tag":"Calculus","q":"Without directly expanding, determine the value of\n\nlim(x → 0)  sin(x) / x","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":"12","metadata":{"number":12,"title":"The Calculus Challenge","grade":"XII","kind":"open-ended","hint":"A standard first-principles / sandwich-theorem limit.","answer":"The limit equals 1."}},{"content_key":"charged-drop","active_date":"2026-11-07","tag":"Physics","q":"A charged oil drop remains stationary between two horizontal charged plates. If the charge on the drop is doubled while everything else remains unchanged, what happens to the drop?","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":"12","metadata":{"number":13,"title":"The Charged-Drop Puzzle","grade":"XII","kind":"open-ended","hint":"At rest, electric force balanced weight. Change one side of the balance.","answer":"The electric force doubles while the weight remains unchanged, so the drop accelerates in the direction of the electric force."}},{"content_key":"circuit-bypass","active_date":"2026-11-08","tag":"Physics","q":"Two identical bulbs are connected in series to a battery. A wire is then connected directly across one bulb. What happens to both bulbs?","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":"12","metadata":{"number":14,"title":"The Circuit Puzzle","grade":"XII","kind":"open-ended","hint":"A wire across a bulb is a short circuit for that branch.","answer":"The bulb bypassed by the wire goes out. The other bulb becomes brighter because the total resistance of the circuit decreases."}},{"content_key":"radioactive-fraction","active_date":"2026-11-09","tag":"Physics","q":"A radioactive sample has a half-life of 10 years. After 30 years, what fraction remains? Can the sample ever become exactly zero?","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":"12","metadata":{"number":15,"title":"The Radioactive Puzzle","grade":"XII","kind":"open-ended","hint":"30 years = 3 half-lives.","answer":"One-eighth remains (½)³. Mathematically, radioactive material approaches zero but does not become exactly zero after any finite time."}},{"content_key":"maximum-product","active_date":"2026-11-10","tag":"Math","q":"Two positive numbers have a fixed sum of 20. What should the numbers be so that their product is maximum?","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":"12","metadata":{"number":16,"title":"The Maximum-Product Puzzle","grade":"XII","kind":"open-ended","hint":"For a fixed sum, the product peaks when the numbers are equal.","answer":"The numbers should be 10 and 10."}},{"content_key":"competitive-s1-q1","active_date":"2026-07-20","tag":"Spatial Reasoning","q":"A large cube of side 5 units is formed by stacking 125 unit cubes and painted red on all six outer faces before being disassembled. How many unit cubes have paint on EXACTLY two faces?","opts":["24","36","48","54"],"correct":1,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":17,"title":"Visual & Spatial Reasoning · 1","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"cubes with exactly 2 painted faces lie on the edges of the cube (excluding corners). There are 12 edges, each with (5−2)=3 such cubes: 12 × 3 = 36."}},{"content_key":"competitive-s1-q2","active_date":"2026-07-21","tag":"Spatial Reasoning","q":"A cube of side 6 units is painted on all faces and cut into 216 unit cubes. How many unit cubes have NO paint on any face?","opts":["48","56","64","72"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":18,"title":"Visual & Spatial Reasoning · 2","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"unpainted cubes form an inner (n−2)³ cube: (6−2)³ = 4³ = 64."}},{"content_key":"competitive-s1-q3","active_date":"2026-07-22","tag":"Spatial Reasoning","q":"A cuboid measuring 4 × 3 × 2 units is painted on all outer faces and cut into unit cubes. How many unit cubes have paint on EXACTLY one face?","opts":["2","4","6","8"],"correct":1,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":19,"title":"Visual & Spatial Reasoning · 3","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"one-face-painted cubes occur only in the interior of each face. On the two 4×3 faces: (4−2)(3−2)=2 each → 4 total. The 3×2 faces give (3−2)(2−2)=0, and the 4×2 faces give (4−2)(2−2)=0. Total = 4."}},{"content_key":"competitive-s1-q4","active_date":"2026-07-23","tag":"Spatial Reasoning","q":"A fair die has 1 opposite 6, 2 opposite 5, and 3 opposite 4. It starts with 1 on top, 2 facing North, 3 facing East, and is rolled (tipped over an edge, without slipping) in this sequence: North, North, East, South. What number is on TOP after all four rolls?","opts":["2","3","4","5"],"correct":3,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":20,"title":"Visual & Spatial Reasoning · 4","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"tracking (Top,Bottom,North,South,East,West) through each roll: Start (1,6,2,5,3,4) → Roll N: (5,2,1,6,3,4) → Roll N: (6,1,5,2,3,4) → Roll E: (4,3,5,2,6,1) → Roll S: (5,2,3,4,6,1). The final top face is 5 (consistent check: every opposite pair still sums to 7)."}},{"content_key":"competitive-s1-q5","active_date":"2026-07-24","tag":"Spatial Reasoning","q":"A cuboid of dimensions 6 × 5 × 4 units is painted on the outside and cut into unit cubes. How many unit cubes have paint on AT LEAST one face?","opts":["88","92","96","100"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":21,"title":"Visual & Spatial Reasoning · 5","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"total cubes = 120. Fully interior (unpainted) cubes = (6−2)(5−2)(4−2) = 4×3×2 = 24. At least one face painted = 120 − 24 = 96."}},{"content_key":"competitive-s1-q6","active_date":"2026-07-25","tag":"Spatial Reasoning","q":"In a sequence of figures, a triangle rotates 45° clockwise at every step AND alternates between fully shaded and half-shaded at every step. Figure 1 is a fully-shaded triangle pointing due North (0°). What is the orientation and shading of Figure 7?","opts":["225°, half-shaded","270°, fully shaded","315°, half-shaded","270°, half-shaded"],"correct":1,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":22,"title":"Visual & Spatial Reasoning · 6","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"rotation at figure n is (n−1)×45°; for n=7 this is 270°. Shading alternates full/half starting 'full' at n=1 (odd numbers), so figure 7 (odd) is fully shaded."}},{"content_key":"competitive-s1-q7","active_date":"2026-07-26","tag":"Spatial Reasoning","q":"A wire is bent into a regular hexagon of side 6 cm. The same wire is straightened and re-bent into a square. Find the side of the square, and state whether the enclosed area increases or decreases, and by roughly how much.","opts":["Side 8 cm; area increases by ~10 cm²","Side 9 cm; area decreases by ~12.5 cm²","Side 9 cm; area increases by ~12.5 cm²","Side 10 cm; area decreases by ~20 cm²"],"correct":1,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":23,"title":"Visual & Spatial Reasoning · 7","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"perimeter = 36 cm in both cases, so the square's side = 9 cm (area 81 cm²). The hexagon's area = (3√3/2)(6²) = 54√3 ≈ 93.53 cm². The area decreases by about 93.53 − 81 ≈ 12.53 cm²."}},{"content_key":"competitive-s1-q8","active_date":"2026-07-27","tag":"Spatial Reasoning","q":"What is the maximum number of non-overlapping regions into which a plane can be divided by 6 straight lines, given no two lines are parallel and no three lines meet at a single point?","opts":["16","19","22","26"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":24,"title":"Visual & Spatial Reasoning · 8","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"the maximum number of regions formed by n lines in general position is 1 + n(n+1)/2. For n=6: 1 + 21 = 22."}},{"content_key":"competitive-s1-q9","active_date":"2026-07-28","tag":"Spatial Reasoning","q":"A circular pizza is cut with 8 straight cuts (chords), where every pair of cuts intersects inside the circle and no three cuts pass through a single point. What is the MAXIMUM number of pieces obtainable?","opts":["29","33","37","41"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":25,"title":"Visual & Spatial Reasoning · 9","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"using the same formula as for lines dividing a plane, maximum pieces = 1 + n(n+1)/2. For n=8: 1 + 36 = 37."}},{"content_key":"competitive-s1-q10","active_date":"2026-07-29","tag":"Spatial Reasoning","q":"A clock's reflection in a vertical mirror placed to its right shows the time as 4:20. What is the ACTUAL time on the clock?","opts":["7:20","7:40","8:20","8:40"],"correct":1,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":26,"title":"Visual & Spatial Reasoning · 10","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"for a standard analogue clock reflected in a vertical mirror, actual time + mirror-image time = 12:00. So actual time = 12:00 − 4:20 = 7:40."}},{"content_key":"competitive-s1-q11","active_date":"2026-07-30","tag":"Spatial Reasoning","q":"A square sheet of paper is folded in half three times in succession (vertical, then horizontal, then vertical again), forming a smaller rectangle with 8 layers. A hole is punched through all the layers at a point that is NOT on any fold crease. How many holes appear when the sheet is fully unfolded?","opts":["4","6","8","16"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":27,"title":"Visual & Spatial Reasoning · 11","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"each fold doubles the number of layers (2³ = 8 layers after 3 folds). Since the punch point avoids every crease, all 8 layers get distinct, non-overlapping holes when unfolded."}},{"content_key":"competitive-s1-q12","active_date":"2026-07-31","tag":"Spatial Reasoning","q":"Equal right-angled isosceles triangles are cut off from all four corners of a square sheet of side 12 cm so that the remaining figure is a REGULAR octagon. Find the side length of the octagon (to 2 decimal places).","opts":["4.32 cm","4.97 cm","5.15 cm","5.52 cm"],"correct":1,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":28,"title":"Visual & Spatial Reasoning · 12","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"let x be the leg of each cut-off triangle. The octagon's side equals both the hypotenuse (x√2) and the leftover straight portion (12−2x) of the original edge. Setting x√2 = 12−2x gives x = 12/(2+√2) ≈ 3.515 cm, so the octagon's side = x√2 ≈ 4.97 cm."}},{"content_key":"competitive-s1-q13","active_date":"2026-08-01","tag":"Spatial Reasoning","q":"A cube of side 4 units is painted BLUE on the top and bottom faces and RED on the four remaining (side) faces, then cut into 64 unit cubes. How many unit cubes have exactly one red face AND exactly one blue face?","opts":["8","12","16","20"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":29,"title":"Visual & Spatial Reasoning · 13","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"such cubes lie on the 8 edges where a blue face meets a red face (the 4 edges bordering the top face and the 4 bordering the bottom face). Each such edge has (4−2)=2 non-corner cubes: 8 × 2 = 16."}},{"content_key":"competitive-s1-q14","active_date":"2026-08-02","tag":"Spatial Reasoning","q":"Three different views of the same standard die are observed: View 1 shows 1 on top, 2 in front, 3 on the right. View 2 shows 4 on top, 1 in front, 6 on the right. View 3 shows 6 on top, 5 in front, 2 on the right. Which number is opposite to 1?","opts":["3","4","5","6"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":30,"title":"Visual & Spatial Reasoning · 14","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"from View 1, faces 2 and 3 are adjacent to 1. From View 2, faces 4 and 6 are adjacent to 1. That accounts for four distinct faces (2, 3, 4, 6) adjacent to face 1; since each face has exactly one opposite face, the only remaining number, 5, must be opposite to 1."}},{"content_key":"competitive-s1-q15","active_date":"2026-08-03","tag":"Spatial Reasoning","q":"A survey of 100 students found: 50 like Mathematics, 40 like Physics, 30 like Chemistry, 20 like both Mathematics and Physics, 15 like both Physics and Chemistry, 10 like both Mathematics and Chemistry, and 5 like all three. How many students like NONE of the three subjects?","opts":["10","15","20","25"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":31,"title":"Visual & Spatial Reasoning · 15","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"by inclusion-exclusion, students liking at least one subject = 50+40+30−20−15−10+5 = 80. Students liking none = 100 − 80 = 20."}},{"content_key":"competitive-s1-q16","active_date":"2026-08-04","tag":"Spatial Reasoning","q":"A convex polygon has exactly 170 diagonals. How many sides does it have, and into how many triangles would it be divided if triangulated from a single vertex?","opts":["18 sides, 16 triangles","19 sides, 17 triangles","20 sides, 18 triangles","22 sides, 20 triangles"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":32,"title":"Visual & Spatial Reasoning · 16","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"diagonals of an n-sided polygon = n(n−3)/2 = 170, giving n² − 3n − 340 = 0, whose positive root is n = 20. Triangulating from one vertex always gives (n−2) triangles = 18."}},{"content_key":"competitive-s1-q17","active_date":"2026-08-05","tag":"Spatial Reasoning","q":"Which of the following capital letters does NOT possess both a horizontal AND a vertical line of symmetry: H, I, O, X, M?","opts":["H","I","X","M"],"correct":3,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":33,"title":"Visual & Spatial Reasoning · 17","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"M has a vertical line of symmetry (left-right mirror) but lacks a horizontal line of symmetry, since its top (two peaks) does not mirror its flat bottom. H, I, O and X all have both."}},{"content_key":"competitive-s1-q18","active_date":"2026-08-06","tag":"Spatial Reasoning","q":"A figure sequence starts with a square (0° rotation, flat side down). At each step the shape gains one more side (square → pentagon → hexagon → …) AND rotates a further 20° clockwise from the previous figure. What shape and total rotation (from the start) appears at the 6th figure?","opts":["Octagon, 80°","Nonagon, 100°","Nonagon, 120°","Decagon, 100°"],"correct":1,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":34,"title":"Visual & Spatial Reasoning · 18","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"figure n has (n+3) sides and rotation (n−1)×20°. For n=6: sides = 9 (a nonagon) and rotation = 5×20° = 100°."}},{"content_key":"competitive-s1-q19","active_date":"2026-08-07","tag":"Spatial Reasoning","q":"A goat is tied to a corner of a square field of side 8 m with a rope 12 m long, and can graze only OUTSIDE the field. Find the total area it can graze. (Use π = 22/7)","opts":["339 3/7 m²","352 m²","364 4/7 m²","376 m²"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":35,"title":"Visual & Spatial Reasoning · 19","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"since the rope (12 m) is longer than the side (8 m), the goat sweeps a 270° sector of radius 12 m at the tied corner, plus a 90° sector of radius (12−8)=4 m at each of the two adjacent corners (where the rope wraps around). Area = (3/4)π(12²) + 2×(1/4)π(4²) = (3/4)(22/7)(144) + (1/2)(22/7)(16) = 339 3/7 + 25 1/7 = 364 4/7 m²."}},{"content_key":"competitive-s1-q20","active_date":"2026-08-08","tag":"Spatial Reasoning","q":"A snail sits at the bottom of a 30-foot well. Each day it climbs 5 feet, but each night it slips back 3 feet (it does not slip once it has reached or crossed the top). On which day does the snail first reach the top?","opts":["Day 13","Day 14","Day 15","Day 27"],"correct":1,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":36,"title":"Visual & Spatial Reasoning · 20","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"net progress per full day-night cycle is 2 feet. After 13 nights, the snail is at 26 feet; on Day 14's climb it reaches 26+5 = 31 feet, crossing the 30-foot mark before it can slip back."}},{"content_key":"competitive-s1-q21","active_date":"2026-08-09","tag":"Spatial Reasoning","q":"Eight people sit around a circular table facing the centre, equally spaced (seats labelled clockwise). E sits directly opposite A. D sits immediately to the right (clockwise) of E. C sits two seats to the right (clockwise) of D. B sits immediately to the left (anticlockwise) of C. F sits directly opposite B. Two seats remain unassigned (for G and H). Who sits immediately to the left of A?","opts":["B","C","D","F"],"correct":1,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":37,"title":"Visual & Spatial Reasoning · 21","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"number seats 1–8 clockwise with A=1. Then E (opposite A) = 5, D (right of E) = 6, C (two seats right of D) = 8, B (left of C) = 7, F (opposite B) = 3. The seat immediately left (anticlockwise) of A (seat 1) is seat 8, which is occupied by C."}},{"content_key":"competitive-s1-q22","active_date":"2026-08-10","tag":"Spatial Reasoning","q":"Using exactly 6 matchsticks of equal length, is it possible to form 4 equilateral triangles such that every matchstick is a side of at least one triangle? If so, what solid is formed?","opts":["No, it is impossible","Yes, a square pyramid","Yes, a regular tetrahedron","Yes, an octahedron"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":38,"title":"Visual & Spatial Reasoning · 22","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"arranging the 6 matchsticks as the 6 edges of a (3-dimensional) regular tetrahedron creates 4 equilateral triangular faces, using each matchstick exactly once."}},{"content_key":"competitive-s1-q23","active_date":"2026-08-11","tag":"Spatial Reasoning","q":"When ALL the diagonals of a regular hexagon are drawn, into how many non-overlapping regions is its interior divided?","opts":["20","22","24","25"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":39,"title":"Visual & Spatial Reasoning · 23","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"a regular hexagon has 9 diagonals, but the 3 main (long) diagonals are concurrent at the centre rather than crossing pairwise. Careful analysis (via Euler's formula: V=19, E=42, giving 24 bounded interior faces) confirms the hexagon is divided into exactly 24 regions — fewer than the 25 that would result if no three diagonals were concurrent."}},{"content_key":"competitive-s1-q24","active_date":"2026-08-12","tag":"Spatial Reasoning","q":"A regular polygon has a number of diagonals that is exactly three times the number of its sides. How many sides does the polygon have?","opts":["7","8","9","10"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":40,"title":"Visual & Spatial Reasoning · 24","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"diagonals = n(n−3)/2 = 3n. Simplifying (n≠0): n−3 = 6, so n = 9. Check: a 9-sided polygon has 9×6/2 = 27 diagonals = 3×9. ✓"}},{"content_key":"competitive-s1-q25","active_date":"2026-08-13","tag":"Spatial Reasoning","q":"At what time between 4 and 5 o'clock will the hour hand and the minute hand of a clock first be exactly opposite each other (180° apart)?","opts":["4:45 5/11","4:50 2/11","4:54 6/11","4:58 8/11"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":41,"title":"Visual & Spatial Reasoning · 25","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"t minutes after 4:00, the hour hand is at (120 + 0.5t)° and the minute hand at 6t°. Setting 6t − (120+0.5t) = 180 gives 5.5t = 300, so t = 54 6/11 minutes."}},{"content_key":"competitive-s1-q26","active_date":"2026-08-14","tag":"Spatial Reasoning","q":"Ten coins are arranged in a triangle pointing upward, with 1, 2, 3, and 4 coins in successive rows (a triangle of side 4). What is the MINIMUM number of coins that must be moved (by sliding, without disturbing the others) to make the triangle point downward instead, keeping the same size and shape?","opts":["2","3","4","5"],"correct":1,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":42,"title":"Visual & Spatial Reasoning · 26","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"this is a classic result: for a side-4 triangular arrangement of 10 coins/balls, the minimum number of coins that must be relocated to invert the triangle's orientation is 3."}},{"content_key":"competitive-s1-q27","active_date":"2026-08-15","tag":"Spatial Reasoning","q":"A 3×3 grid follows a Sudoku-like rule: every row and every column contains exactly one Circle, one Square, and one Triangle. Row 1 = Circle, Square, Triangle. Row 2 = Square, Triangle, Circle. Row 3 = Triangle, ?, Square. What shape belongs in Row 3, Column 2?","opts":["Circle","Square","Triangle","Cannot be determined"],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":43,"title":"Visual & Spatial Reasoning · 27","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"Column 2 already has Square (Row 1) and Triangle (Row 2), so the only shape available for Row 3 is Circle."}},{"content_key":"competitive-s1-q28","active_date":"2026-08-16","tag":"Spatial Reasoning","q":"A 2×2 grid has exactly one quadrant shaded. In each successive figure, the shaded quadrant rotates 90° clockwise (top-left → top-right → bottom-right → bottom-left → top-left …). If the shaded quadrant is top-left in Figure 1, which quadrant is shaded in Figure 10?","opts":["Top-left","Top-right","Bottom-right","Bottom-left"],"correct":1,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":44,"title":"Visual & Spatial Reasoning · 28","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"the cycle length is 4; Figure 10 corresponds to position ((10−1) mod 4) = 1 in the cycle (0-indexed), i.e. the 2nd position, which is top-right."}},{"content_key":"competitive-s1-q29","active_date":"2026-08-17","tag":"Spatial Reasoning","q":"A person starts facing North, turns 90° clockwise, then 180°, and finally 90° anticlockwise. He then walks forward and turns to face directly away from his starting direction. Which direction is he now facing?","opts":["North","East","South","West"],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":45,"title":"Visual & Spatial Reasoning · 29","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"North(0°)+90°cw=East(90°); +180°=West(270°); −90°(acw)=South(180°). Facing 'directly away' from South means facing North (the opposite direction), so the final direction is North."}},{"content_key":"competitive-s1-q30","active_date":"2026-08-18","tag":"Spatial Reasoning","q":"What is the minimum number of straight cuts needed to divide a circular cake into exactly 11 pieces, if every pair of cuts must intersect inside the circle and no three cuts may meet at one point?","opts":["4","5","6","7"],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":46,"title":"Visual & Spatial Reasoning · 30","grade":"Competitive","kind":"mcq","hint":"Sketch the arrangement and track only the information that changes.","answer":"using the maximum-regions formula 1 + n(n+1)/2: for n=4, this gives 1+10=11 pieces, the smallest n for which the count reaches (or exceeds) 11."}},{"content_key":"competitive-s2-q1","active_date":"2026-08-19","tag":"Logical Reasoning","q":"The present ages of A and B are in the ratio 5:6. Eight years ago, the ratio of their ages was 3:4. Find the SUM of their present ages.","opts":["40","44","48","52"],"correct":1,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":47,"title":"Logical & Analytical Reasoning · 1","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"let present ages be 5x and 6x. (5x−8)/(6x−8) = 3/4 gives 20x−32 = 18x−24, so x=4. Ages are 20 and 24; sum = 44."}},{"content_key":"competitive-s2-q2","active_date":"2026-08-20","tag":"Logical Reasoning","q":"The sum of the present ages of a father, mother, and son is 92 years. Five years ago, the ratio of the father's age to the son's age was 7:2. The mother is presently 3 years younger than the father. Find the present age of the son.","opts":["10","12","15","18"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":48,"title":"Logical & Analytical Reasoning · 2","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"let ages 5 years ago be 7k (father) and 2k (son). Present ages: father=7k+5, son=2k+5, mother=(7k+5)−3=7k+2. Sum: (7k+5)+(2k+5)+(7k+2)=16k+12=92, so k=5. Son's present age = 2(5)+5 = 15."}},{"content_key":"competitive-s2-q3","active_date":"2026-08-21","tag":"Logical Reasoning","q":"A and B together can finish a work in 12 days. B and C together finish it in 15 days. A and C together finish it in 20 days. In how many days can A ALONE finish the work?","opts":["24","27","30","36"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":49,"title":"Logical & Analytical Reasoning · 3","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"adding all three equations: 2(1/A+1/B+1/C) = 1/12+1/15+1/20 = 12/60 = 1/5, so 1/A+1/B+1/C = 1/10. Then 1/A = 1/10 − 1/15 = 1/30, so A alone takes 30 days."}},{"content_key":"competitive-s2-q4","active_date":"2026-08-22","tag":"Logical Reasoning","q":"A boat travels 30 km upstream and 44 km downstream in 10 hours; it also travels 40 km upstream and 55 km downstream in 13 hours. Find the speed of the boat in still water.","opts":["6 km/hr","7 km/hr","8 km/hr","9 km/hr"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":50,"title":"Logical & Analytical Reasoning · 4","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"let x=1/(upstream speed), y=1/(downstream speed). From the two equations, 30x+44y=10 and 40x+55y=13, solving gives x=1/5, y=1/11, so upstream speed=5 km/hr and downstream speed=11 km/hr. Boat speed in still water = (5+11)/2 = 8 km/hr (stream speed = 3 km/hr)."}},{"content_key":"competitive-s2-q5","active_date":"2026-08-23","tag":"Logical Reasoning","q":"A vessel contains milk and water in the ratio 5:3. When 16 litres of the mixture is removed and replaced with pure water, the new ratio of milk to water becomes 5:7. Find the original quantity of mixture in the vessel.","opts":["32 L","40 L","48 L","56 L"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":51,"title":"Logical & Analytical Reasoning · 5","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"let the total be 8x (milk 5x, water 3x). Removing 16 L takes out 10 L milk and 6 L water; adding 16 L pure water gives milk=5x−10, water=3x+10. Setting (5x−10)/(3x+10)=5/7 gives x=6, so total = 8x = 48 litres."}},{"content_key":"competitive-s2-q6","active_date":"2026-08-24","tag":"Logical Reasoning","q":"In the cryptarithm BASE + BALL = GAMES, each letter stands for a unique digit (0–9) and no number has a leading zero. Find the value of GAMES.","opts":["13984","14938","15827","16745"],"correct":1,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":52,"title":"Logical & Analytical Reasoning · 6","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"the unique solution is B=7, A=4, S=8, E=3, L=5, G=1, M=9, giving BASE=7483, BALL=7455, and their sum GAMES=14938."}},{"content_key":"competitive-s2-q7","active_date":"2026-08-25","tag":"Logical Reasoning","q":"In how many ways can the letters of the word 'ORANGE' be arranged so that all the vowels occupy ONLY the odd positions (1st, 3rd, 5th)?","opts":["12","18","24","36"],"correct":3,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":53,"title":"Logical & Analytical Reasoning · 7","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"ORANGE has 3 vowels (O,A,E) and 3 consonants (R,N,G). The 3 vowels can be arranged in the 3 odd positions in 3!=6 ways, and the 3 consonants in the 3 even positions in 3!=6 ways: 6×6=36."}},{"content_key":"competitive-s2-q8","active_date":"2026-08-26","tag":"Logical Reasoning","q":"Three fair dice are rolled together. What is the probability that the sum of the numbers obtained is exactly 10?","opts":["1/9","1/8","5/36","1/6"],"correct":1,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":54,"title":"Logical & Analytical Reasoning · 8","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"out of 216 equally likely outcomes, exactly 27 combinations give a sum of 10 (a known result for 3 dice). Probability = 27/216 = 1/8."}},{"content_key":"competitive-s2-q9","active_date":"2026-08-27","tag":"Logical Reasoning","q":"In how many ways can 6 people be seated around a circular table such that two particular people do NOT sit next to each other?","opts":["48","60","72","96"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":55,"title":"Logical & Analytical Reasoning · 9","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"total circular arrangements of 6 people = (6−1)! = 120. Arrangements with the two together (treating them as one block) = (5−1)!×2 = 48. Arrangements with them apart = 120−48 = 72."}},{"content_key":"competitive-s2-q10","active_date":"2026-08-28","tag":"Logical Reasoning","q":"Find the smallest positive integer that leaves a remainder of 2 when divided by 3, a remainder of 3 when divided by 4, a remainder of 4 when divided by 5, and a remainder of 5 when divided by 6.","opts":["39","49","59","119"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":56,"title":"Logical & Analytical Reasoning · 10","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"in every case, the remainder is exactly one less than the divisor, so the number is 1 less than a common multiple of 3, 4, 5, and 6. LCM(3,4,5,6)=60, so the smallest such number is 60−1=59."}},{"content_key":"competitive-s2-q11","active_date":"2026-08-29","tag":"Logical Reasoning","q":"A group of 150 people were surveyed: 80 read Newspaper A, 70 read B, 60 read C, 30 read both A and B, 25 read both B and C, 20 read both A and C, and 10 read all three. How many people read EXACTLY ONE newspaper?","opts":["80","85","90","95"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":57,"title":"Logical & Analytical Reasoning · 11","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"Exactly A = 80−30−20+10=40; Exactly B = 70−30−25+10=25; Exactly C = 60−25−20+10=25. Total exactly one = 40+25+25 = 90."}},{"content_key":"competitive-s2-q12","active_date":"2026-08-30","tag":"Logical Reasoning","q":"A sum invested at compound interest (compounded annually) amounts to ₹4,840 in 2 years and ₹5,324 in 3 years. Find the rate of interest and the original principal.","opts":["8%, ₹4200","9%, ₹4100","10%, ₹4000","12%, ₹3800"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":58,"title":"Logical & Analytical Reasoning · 12","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"the ratio of successive amounts gives (1+r) = 5324/4840 = 1.1, so r=10%. Then P(1.1)²=4840 gives P=4000."}},{"content_key":"competitive-s2-q13","active_date":"2026-08-31","tag":"Logical Reasoning","q":"Two trains, 120 m and 180 m long, run on parallel tracks. Running in the SAME direction, the faster train passes the slower one in 30 seconds. Running in OPPOSITE directions, they cross each other in 6 seconds. Find the speed of the faster train (in km/hr).","opts":["90 km/hr","96 km/hr","102 km/hr","108 km/hr"],"correct":3,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":59,"title":"Logical & Analytical Reasoning · 13","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"let speeds be x, y (m/s), x>y, combined length=300 m. Same direction: 300/(x−y)=30 → x−y=10. Opposite direction: 300/(x+y)=6 → x+y=50. Solving: x=30 m/s = 108 km/hr, y=20 m/s = 72 km/hr."}},{"content_key":"competitive-s2-q14","active_date":"2026-09-01","tag":"Logical Reasoning","q":"Using Zeller's Congruence (or the doomsday method), determine the day of the week for 15th August 1947.","opts":["Thursday","Friday","Saturday","Sunday"],"correct":1,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":60,"title":"Logical & Analytical Reasoning · 14","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"applying Zeller's congruence for 15 August 1947 (q=15, m=8, K=47, J=19) gives h=(15+23+47+11+4−38) mod 7 = 62 mod 7 = 6, which corresponds to Friday. (This matches the well-documented historical fact that India's Independence Day fell on a Friday.)"}},{"content_key":"competitive-s2-q15","active_date":"2026-09-02","tag":"Logical Reasoning","q":"Find the next term: 4, 9, 25, 49, 121, ?","opts":["144","169","196","225"],"correct":1,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":61,"title":"Logical & Analytical Reasoning · 15","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"the terms are squares of consecutive prime numbers: 2², 3², 5², 7², 11², 13² → 169."}},{"content_key":"competitive-s2-q16","active_date":"2026-09-03","tag":"Logical Reasoning","q":"A four-digit palindrome (reads the same forwards and backwards) has a digit sum of 18, and its first digit is exactly twice its second digit. Find the number.","opts":["4224","5115","6336","7227"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":62,"title":"Logical & Analytical Reasoning · 16","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"a 4-digit palindrome has the form abba, with digit sum 2(a+b)=18, so a+b=9. Given a=2b: 3b=9, so b=3, a=6. The number is 6336."}},{"content_key":"competitive-s2-q17","active_date":"2026-09-04","tag":"Logical Reasoning","q":"A and B start from the same point on a circular track of circumference 600 m, walking in OPPOSITE directions at 5 m/s and 7 m/s respectively. After how many seconds will they meet for the THIRD time?","opts":["100 s","125 s","150 s","175 s"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":63,"title":"Logical & Analytical Reasoning · 17","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"moving in opposite directions, their relative speed is 12 m/s, and they meet each time their combined distance covered equals a multiple of 600 m. The third meeting occurs when combined distance = 1800 m, so time = 1800/12 = 150 seconds."}},{"content_key":"competitive-s2-q18","active_date":"2026-09-05","tag":"Logical Reasoning","q":"A, B, and C invest ₹4000, ₹6000, and ₹8000 respectively in a business, for periods of 8, 6, and 9 months respectively. If the total profit at the end of the year is ₹35,000, find C's share.","opts":["₹14,000","₹16,000","₹18,000","₹20,000"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":64,"title":"Logical & Analytical Reasoning · 18","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"profit shares are proportional to (investment × time): A:32000, B:36000, C:72000, simplifying to the ratio 8:9:18 (35 parts total). Each part = 35000/35 = ₹1000, so C's share = 18×1000 = ₹18,000."}},{"content_key":"competitive-s2-q19","active_date":"2026-09-06","tag":"Logical Reasoning","q":"Find the next term: 2, 5, 10, 17, 26, 37, ?","opts":["46","48","50","52"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":65,"title":"Logical & Analytical Reasoning · 19","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"each term equals n²+1 for n=1,2,3,…: 1²+1=2, 2²+1=5, …, 7²+1=50."}},{"content_key":"competitive-s2-q20","active_date":"2026-09-07","tag":"Logical Reasoning","q":"On an island, every inhabitant is either a Knight (always tells the truth) or a Knave (always lies). A says, 'B is a Knave.' B says, 'A and C are of the same type (both Knights or both Knaves).' What can be determined with certainty about C?","opts":["C is a Knight","C is a Knave","C could be either","No conclusion possible"],"correct":1,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":66,"title":"Logical & Analytical Reasoning · 20","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"testing both possibilities for A: if A is a Knight, B is indeed a Knave (as A truthfully says), so B's statement is false, meaning A and C are of DIFFERENT types; since A is a Knight, C must be a Knave. If A is a Knave, then B (contradicting A's false claim) is a Knight, so B's statement is true, meaning A and C are the SAME type; since A is a Knave, C is also a Knave. Either way, C is a Knave."}},{"content_key":"competitive-s2-q21","active_date":"2026-09-08","tag":"Logical Reasoning","q":"A man travels from city X to city Y at 40 km/hr and returns from Y to X at 60 km/hr. Find his AVERAGE speed for the entire round trip.","opts":["45 km/hr","48 km/hr","50 km/hr","52 km/hr"],"correct":1,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":67,"title":"Logical & Analytical Reasoning · 21","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"for equal distances at two different speeds, average speed = 2ab/(a+b) = 2×40×60/100 = 48 km/hr (NOT the simple average of 50 km/hr, which is a common mistake)."}},{"content_key":"competitive-s2-q22","active_date":"2026-09-09","tag":"Logical Reasoning","q":"A shopkeeper mixes three varieties of rice costing ₹20, ₹25, and ₹30 per kg in the ratio 2:3:5 by weight. Find the cost per kg of the resulting mixture.","opts":["₹25.00","₹26.00","₹26.50","₹27.00"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":68,"title":"Logical & Analytical Reasoning · 22","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"weighted average = (2×20 + 3×25 + 5×30)/(2+3+5) = (40+75+150)/10 = 265/10 = ₹26.50."}},{"content_key":"competitive-s2-q23","active_date":"2026-09-10","tag":"Logical Reasoning","q":"From a standard well-shuffled deck of 52 cards, 4 cards are drawn at random. What is the probability that all four are of DIFFERENT suits?","opts":["2197/20825","1/24","13/204","1/16"],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":69,"title":"Logical & Analytical Reasoning · 23","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"favourable outcomes = 13×13×13×13 = 13⁴ = 28561 (one card from each suit). Total ways to choose 4 cards = C(52,4) = 270725. The probability simplifies to 2197/20825 ≈ 0.1055."}},{"content_key":"competitive-s2-q24","active_date":"2026-09-11","tag":"Logical Reasoning","q":"An item's marked price is 40% above its cost price. After two successive discounts of 10% and 15% on the marked price, it is sold for ₹1071. Find the cost price.","opts":["₹900","₹950","₹1000","₹1050"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":70,"title":"Logical & Analytical Reasoning · 24","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"final price = CP × 1.40 × 0.90 × 0.85 = CP × 1.071. Setting this equal to 1071 gives CP = ₹1000."}},{"content_key":"competitive-s2-q25","active_date":"2026-09-12","tag":"Logical Reasoning","q":"A trader spends exactly ₹740 buying pens at ₹18 each and pencils at ₹7 each (buying at least one of each). The number of pens bought is more than the number of pencils, and the number of pencils is at least 20. Find the number of pens and pencils bought.","opts":["24 pens, 44 pencils","31 pens, 26 pencils","38 pens, 8 pencils","10 pens, 80 pencils"],"correct":1,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":71,"title":"Logical & Analytical Reasoning · 25","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"solving 18p+7c=740 for positive integers with p>c≥20 gives the unique solution p=31, c=26 (checking: 18×31+7×26 = 558+182 = 740 ✓; the other integer solution, p=38,c=8, is excluded since it violates c≥20)."}},{"content_key":"competitive-s2-q26","active_date":"2026-09-13","tag":"Logical Reasoning","q":"In a standard 3×3 magic square (numbers 1–9, every row/column/diagonal summing to 15), the number 2 is placed in the top-right corner. What number must occupy the bottom-left corner?","opts":["4","6","7","8"],"correct":3,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":72,"title":"Logical & Analytical Reasoning · 26","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"the top-right and bottom-left corners lie on the same diagonal as the centre (which is always 5 in a 3×3 magic square). Since that diagonal sums to 15, the bottom-left corner = 15 − 5 − 2 = 8."}},{"content_key":"competitive-s2-q27","active_date":"2026-09-14","tag":"Logical Reasoning","q":"A sequence is defined by T₁=3, T₂=7, and Tₙ = Tₙ₋₁ + Tₙ₋₂ + 2 for n≥3. Find T₆.","opts":["46","52","58","64"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":73,"title":"Logical & Analytical Reasoning · 27","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"computing successively: T₃=7+3+2=12, T₄=12+7+2=21, T₅=21+12+2=35, T₆=35+21+2=58."}},{"content_key":"competitive-s2-q28","active_date":"2026-09-15","tag":"Logical Reasoning","q":"Pipe A can fill a tank in 20 hours; Pipe B can empty a full tank in 30 hours. Both are opened together, but Pipe B is closed after 10 hours. How much MORE time will Pipe A alone take to completely fill the tank?","opts":["15 hours","16⅔ hours","18 hours","20 hours"],"correct":1,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":74,"title":"Logical & Analytical Reasoning · 28","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"in 10 hours, the combined (fill−empty) rate fills 10×(1/20−1/30)=10×(1/60)=1/6 of the tank. The remaining 5/6 is filled by Pipe A alone at 1/20 per hour, taking (5/6)÷(1/20) = 100/6 = 16⅔ hours."}},{"content_key":"competitive-s2-q29","active_date":"2026-09-16","tag":"Logical Reasoning","q":"In how many ways can 5 letters be placed into 5 distinctly addressed envelopes (one letter per envelope) such that NO letter goes into its correctly addressed envelope?","opts":["24","36","44","60"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":75,"title":"Logical & Analytical Reasoning · 29","grade":"Competitive","kind":"mcq","hint":"List the constraints first, then eliminate impossible cases.","answer":"this is the derangement D₅ = 5!×(1−1/1!+1/2!−1/3!+1/4!−1/5!) = 120 × (11/30) = 44."}},{"content_key":"competitive-s3-q1","active_date":"2026-09-17","tag":"Mathematics","q":"Let f: ℝ → ℝ satisfy f(x+y) = f(x) + f(y) + xy for all real x, y, and f(1) = 1. Find f(10).","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":76,"title":"Mathematics Olympiad · 1","grade":"Competitive","kind":"open-ended","hint":"Look for a useful identity, invariant, or extremal case.","answer":"55\n\nTrying f(x) = x²/2 + cx satisfies the functional equation for any constant c (since f(x+y)−f(x)−f(y) = xy holds identically). Using f(1)=1: 1/2+c=1, so c=1/2, giving f(x) = x(x+1)/2. Then f(10) = 10×11/2 = 55."}},{"content_key":"competitive-s3-q2","active_date":"2026-09-18","tag":"Mathematics","q":"If a, b, c are positive real numbers with a+b+c=9, find the MAXIMUM possible value of abc.","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":77,"title":"Mathematics Olympiad · 2","grade":"Competitive","kind":"open-ended","hint":"Look for a useful identity, invariant, or extremal case.","answer":"27 (attained when a=b=c=3)\n\nBy the AM-GM inequality, (a+b+c)/3 ≥ (abc)^(1/3), so abc ≤ ((a+b+c)/3)³ = 3³ = 27, with equality when a=b=c=3."}},{"content_key":"competitive-s3-q3","active_date":"2026-09-19","tag":"Mathematics","q":"Find the smallest positive integer N such that N leaves remainder 5 when divided by 7, remainder 7 when divided by 9, and remainder 9 when divided by 11.","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":78,"title":"Mathematics Olympiad · 3","grade":"Competitive","kind":"open-ended","hint":"Look for a useful identity, invariant, or extremal case.","answer":"691\n\nIn every case the remainder is exactly 2 less than the divisor, so N ≡ −2 (mod 7, 9, and 11). Thus N+2 is divisible by lcm(7,9,11) = 693. The smallest positive N is 693−2 = 691."}},{"content_key":"competitive-s3-q4","active_date":"2026-09-20","tag":"Mathematics","q":"What is the minimum number of people needed in a room to GUARANTEE that at least 3 of them were born in the same month?","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":79,"title":"Mathematics Olympiad · 4","grade":"Competitive","kind":"open-ended","hint":"Look for a useful identity, invariant, or extremal case.","answer":"25\n\nBy the pigeonhole principle, with 12 months (pigeonholes), to force at least 3 people into some month, we need more than 2×12=24 people, i.e., at least 25."}},{"content_key":"competitive-s3-q5","active_date":"2026-09-21","tag":"Mathematics","q":"Two circles of radii 8 cm and 3 cm have their centres 13 cm apart. Find the length of their DIRECT common tangent.","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":80,"title":"Mathematics Olympiad · 5","grade":"Competitive","kind":"open-ended","hint":"Look for a useful identity, invariant, or extremal case.","answer":"12 cm\n\nFor two circles with centre distance d and radii r₁, r₂, the direct common tangent length = √(d² − (r₁−r₂)²) = √(13² − 5²) = √(169−25) = √144 = 12."}},{"content_key":"competitive-s3-q6","active_date":"2026-09-22","tag":"Mathematics","q":"A sequence satisfies a₁=1, a₂=3, and aₙ = 3aₙ₋₁ − 2aₙ₋₂ for n≥3. Find a₆.","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":81,"title":"Mathematics Olympiad · 6","grade":"Competitive","kind":"open-ended","hint":"Look for a useful identity, invariant, or extremal case.","answer":"63\n\nThe characteristic equation x²−3x+2=0 factors as (x−1)(x−2)=0, giving general solution aₙ = A + B·2ⁿ. Using a₁=1, a₂=3: A+2B=1, A+4B=3, giving B=1, A=−1, so aₙ = 2ⁿ−1. Thus a₆ = 2⁶−1 = 63 (verified directly: 1,3,7,15,31,63,…)."}},{"content_key":"competitive-s3-q7","active_date":"2026-09-23","tag":"Mathematics","q":"Find all positive integers n such that n² + 24 is a perfect square, and give the SUM of all such values of n.","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":82,"title":"Mathematics Olympiad · 7","grade":"Competitive","kind":"open-ended","hint":"Look for a useful identity, invariant, or extremal case.","answer":"n=1 and n=5; sum = 6\n\nLet n²+24=k², so (k−n)(k+n)=24. Since k−n and k+n must have the same parity and their product is even, both must be even. Checking even factor pairs of 24 with k−n < k+n: (2,12) gives n=5, k=7; (4,6) gives n=1, k=5. These are the only solutions. Verification: 1²+24=25=5², 5²+24=49=7²."}},{"content_key":"competitive-s3-q8","active_date":"2026-09-24","tag":"Mathematics","q":"In triangle ABC, D and E lie on AB and AC respectively with DE parallel to BC, and AD:DB = 2:3. Find the ratio of the area of triangle ADE to the area of quadrilateral DBCE.","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":83,"title":"Mathematics Olympiad · 8","grade":"Competitive","kind":"open-ended","hint":"Look for a useful identity, invariant, or extremal case.","answer":"4 : 21\n\nSince DE∥BC, triangle ADE ~ triangle ABC with ratio AD:AB = 2:5. So area(ADE):area(ABC) = 4:25. Taking area(ABC)=25 units, area(ADE)=4, so area(DBCE)=25−4=21. The required ratio is 4:21."}},{"content_key":"competitive-s3-q9","active_date":"2026-09-25","tag":"Mathematics","q":"How many distinct necklaces can be made using 4 red beads and 2 blue beads (6 beads total) arranged in a circle, where rotations are considered identical but reflections are considered different?","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":84,"title":"Mathematics Olympiad · 9","grade":"Competitive","kind":"open-ended","hint":"Look for a useful identity, invariant, or extremal case.","answer":"3 distinct necklaces\n\nUsing Burnside's lemma over the cyclic group C₆ of rotations: identity fixes C(6,2)=15 arrangements; rotations by 1 and 5 positions fix 0 (would require all beads identical); rotations by 2 and 4 positions (each splitting the necklace into 2 cycles of length 3) fix 0 (2 blue beads can't be split into multiples of 3 per cycle); rotation by 3 positions (splitting into 3 cycles of length 2) fixes 3 arrangements (choose which of the 3 cycles is blue). Average = (15+0+0+3+0+0)/6 = 18/6 = 3."}},{"content_key":"competitive-s3-q10","active_date":"2026-09-26","tag":"Mathematics","q":"A factory has machines A, B, and C producing 25%, 35%, and 40% of total output, with defect rates 5%, 4%, and 2% respectively. If a randomly chosen item is found defective, find the probability it was produced by machine C.","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":85,"title":"Mathematics Olympiad · 10","grade":"Competitive","kind":"open-ended","hint":"Look for a useful identity, invariant, or extremal case.","answer":"16/69 ≈ 0.232 (about 23.2%)\n\nUsing Bayes' theorem: P(defective) = 0.25×0.05 + 0.35×0.04 + 0.40×0.02 = 0.0125+0.014+0.008 = 0.0345. P(C | defective) = 0.008/0.0345 = 16/69 ≈ 0.232."}},{"content_key":"competitive-s3-q11","active_date":"2026-09-27","tag":"Mathematics","q":"If x+y+z=6, xy+yz+zx=11, and xyz=6, find the value of x³+y³+z³.","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":86,"title":"Mathematics Olympiad · 11","grade":"Competitive","kind":"open-ended","hint":"Look for a useful identity, invariant, or extremal case.","answer":"36\n\nUsing x²+y²+z² = (x+y+z)²−2(xy+yz+zx) = 36−22=14, and the identity x³+y³+z³−3xyz = (x+y+z)(x²+y²+z²−xy−yz−zx) = 6×(14−11) = 18. So x³+y³+z³ = 18+3(6) = 36. (Indeed x,y,z are the roots 1, 2, 3 of t³−6t²+11t−6=0, and 1³+2³+3³=1+8+27=36.)"}},{"content_key":"competitive-s3-q12","active_date":"2026-09-28","tag":"Mathematics","q":"Find the last two digits of 7^2023.","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":87,"title":"Mathematics Olympiad · 12","grade":"Competitive","kind":"open-ended","hint":"Look for a useful identity, invariant, or extremal case.","answer":"43\n\nWe need 7^2023 mod 100. Computing powers of 7 mod 100: 7¹=7, 7²=49, 7³=43, 7⁴=1 (mod 100) — so 7 has order 4 modulo 100. Since 2023 mod 4 = 3, 7^2023 ≡ 7³ ≡ 43 (mod 100)."}},{"content_key":"competitive-s3-q13","active_date":"2026-09-29","tag":"Mathematics","q":"ABCD is a cyclic quadrilateral with AB=5, BC=6, CD=7, DA=8. Using Ptolemy's theorem (AC×BD = AB×CD + BC×DA), find the product of its diagonals AC×BD.","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":88,"title":"Mathematics Olympiad · 13","grade":"Competitive","kind":"open-ended","hint":"Look for a useful identity, invariant, or extremal case.","answer":"83\n\nBy Ptolemy's theorem: AC×BD = AB×CD + BC×DA = (5×7) + (6×8) = 35+48 = 83."}},{"content_key":"competitive-s3-q14","active_date":"2026-09-30","tag":"Mathematics","q":"In how many ways can 20 identical chocolates be distributed among 4 children such that each child receives at least 2 but no more than 8 chocolates?","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":89,"title":"Mathematics Olympiad · 14","grade":"Competitive","kind":"open-ended","hint":"Look for a useful identity, invariant, or extremal case.","answer":"231\n\nSubstituting yᵢ=xᵢ−2 (so 0≤yᵢ≤6) transforms the condition to y₁+y₂+y₃+y₄=12. Without the upper bound, solutions = C(12+3,3)=C(15,3)=455. Subtract cases where some yᵢ≥7 (via yᵢ'=yᵢ−7): for each of the 4 variables, remaining solutions = C(5+3,3)=C(8,3)=56, giving 4×56=224 to subtract (no double-counting is possible since two variables can't both exceed 6 when the total is only 12). Valid distributions = 455−224 = 231."}},{"content_key":"competitive-s3-q15","active_date":"2026-10-01","tag":"Mathematics","q":"Find the sum: 1/(1×2) + 1/(2×3) + 1/(3×4) + … + 1/(19×20).","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":90,"title":"Mathematics Olympiad · 15","grade":"Competitive","kind":"open-ended","hint":"Look for a useful identity, invariant, or extremal case.","answer":"19/20\n\nEach term telescopes: 1/(n(n+1)) = 1/n − 1/(n+1). The sum collapses to 1/1 − 1/20 = 19/20."}},{"content_key":"competitive-s3-q16","active_date":"2026-10-02","tag":"Mathematics","q":"Find the number of trailing zeros when 15! is written in BASE 12.","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":91,"title":"Mathematics Olympiad · 16","grade":"Competitive","kind":"open-ended","hint":"Look for a useful identity, invariant, or extremal case.","answer":"5 trailing zeros\n\n12 = 2²×3, so the number of trailing zeros equals min(⌊v₂(15!)/2⌋, v₃(15!)), where v₂ and v₃ are the exponents of 2 and 3 in 15!. v₂(15!) = ⌊15/2⌋+⌊15/4⌋+⌊15/8⌋ = 7+3+1 = 11. v₃(15!) = ⌊15/3⌋+⌊15/9⌋ = 5+1 = 6. min(⌊11/2⌋, 6) = min(5,6) = 5."}},{"content_key":"competitive-s3-q17","active_date":"2026-10-03","tag":"Mathematics","q":"A triangle has sides 9, 10, and 17. Find its inradius.","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":92,"title":"Mathematics Olympiad · 17","grade":"Competitive","kind":"open-ended","hint":"Look for a useful identity, invariant, or extremal case.","answer":"2\n\nSemi-perimeter s = (9+10+17)/2 = 18. Area = √(s(s−a)(s−b)(s−c)) = √(18×9×8×1) = √1296 = 36. Inradius r = Area/s = 36/18 = 2."}},{"content_key":"competitive-s3-q18","active_date":"2026-10-04","tag":"Mathematics","q":"Find the minimum value of x²+y² given x+y=10, first for positive real x,y, and then for positive INTEGER x,y with x≠y.","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":93,"title":"Mathematics Olympiad · 18","grade":"Competitive","kind":"open-ended","hint":"Look for a useful identity, invariant, or extremal case.","answer":"Real minimum = 50 (at x=y=5); integer (x≠y) minimum = 52 (at x=4,y=6)\n\nFor reals, by symmetry (or Cauchy-Schwarz/QM-AM), the minimum occurs at x=y=5, giving x²+y²=50. For positive integers with x≠y, the closest possible pair to (5,5) is (4,6) [or (6,4)], giving 16+36=52, which is smaller than any other integer pair (e.g. (3,7) gives 58)."}},{"content_key":"competitive-s3-q19","active_date":"2026-10-05","tag":"Mathematics","q":"From a group of 6 men and 4 women, a committee of 5 is formed with AT LEAST 2 women. In how many ways can this be done?","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":94,"title":"Mathematics Olympiad · 19","grade":"Competitive","kind":"open-ended","hint":"Look for a useful identity, invariant, or extremal case.","answer":"186\n\nSumming over w=2,3,4 women: w=2: C(4,2)×C(6,3)=6×20=120; w=3: C(4,3)×C(6,2)=4×15=60; w=4: C(4,4)×C(6,1)=1×6=6. Total = 120+60+6 = 186."}},{"content_key":"competitive-s3-q20","active_date":"2026-10-06","tag":"Mathematics","q":"Find the remainder when 3^100 is divided by 101 (given that 101 is a prime number).","opts":[],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":95,"title":"Mathematics Olympiad · 20","grade":"Competitive","kind":"open-ended","hint":"Look for a useful identity, invariant, or extremal case.","answer":"1\n\nBy Fermat's Little Theorem, since 101 is prime and gcd(3,101)=1, we have 3^100 ≡ 1 (mod 101)."}},{"content_key":"competitive-s4-q1","active_date":"2026-10-07","tag":"General Knowledge","q":"Consider the following statements regarding the Indian Constitution:\n1. The Right to Property was a Fundamental Right until removed by the 44th Constitutional Amendment Act, 1978, becoming a legal right under Article 300-A.\n2. Directive Principles of State Policy are justiciable, meaning courts can directly enforce them.\n3. The Ninth Schedule (Article 31-B) was originally added to protect land reform laws from judicial review.\nWhich of the statements given above is/are correct?","opts":["1 and 3 only","2 only","1, 2 and 3","1 only"],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":96,"title":"General Knowledge · 1","grade":"Competitive","kind":"mcq","hint":"Check each statement independently before combining your choices.","answer":"Statement 2 is false: Directive Principles are explicitly non-justiciable under Article 37; they guide governance but cannot be enforced by courts."}},{"content_key":"competitive-s4-q2","active_date":"2026-10-08","tag":"General Knowledge","q":"Consider the following pairs:\n1. Quit India Movement — 1942\n2. Cripps Mission — 1942\n3. Cabinet Mission Plan — 1946\n4. Poona Pact — 1932\nHow many of the above pairs are correctly matched?","opts":["One","Two","Three","All four"],"correct":3,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":97,"title":"General Knowledge · 2","grade":"Competitive","kind":"mcq","hint":"Check each statement independently before combining your choices.","answer":"the Quit India Movement (August 1942), Cripps Mission (March 1942), Cabinet Mission Plan (1946), and Poona Pact between Gandhi and Ambedkar (1932) are all correctly dated."}},{"content_key":"competitive-s4-q3","active_date":"2026-10-09","tag":"General Knowledge","q":"Consider the following statements about Indian rivers:\n1. The Narmada and the Tapi are the only two major peninsular rivers that flow from east to west, draining into the Arabian Sea via estuaries rather than deltas.\n2. The Godavari, called the 'Dakshin Ganga', is the largest peninsular river by both length and basin size.\n3. The Chambal is a direct tributary of the Ganga.\nWhich of the statements given above is/are correct?","opts":["1 only","1 and 2 only","2 and 3 only","1, 2 and 3"],"correct":1,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":98,"title":"General Knowledge · 3","grade":"Competitive","kind":"mcq","hint":"Check each statement independently before combining your choices.","answer":"Statement 3 is incorrect: the Chambal is a tributary of the Yamuna, which itself joins the Ganga; the Chambal does not join the Ganga directly."}},{"content_key":"competitive-s4-q4","active_date":"2026-10-10","tag":"General Knowledge","q":"Consider the following statements regarding Emergency provisions under the Indian Constitution:\n1. A National Emergency under Article 352 can be proclaimed only on grounds of war, external aggression, or armed rebellion.\n2. The term 'internal disturbance' in Article 352 was replaced by 'armed rebellion' through the 44th Constitutional Amendment Act.\n3. A Proclamation of Emergency must be approved by both Houses of Parliament within one month of its issue.\nWhich of the statements given above is/are correct?","opts":["1 and 2 only","2 and 3 only","1 and 3 only","1, 2 and 3"],"correct":3,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":99,"title":"General Knowledge · 4","grade":"Competitive","kind":"mcq","hint":"Check each statement independently before combining your choices.","answer":"all three statements accurately describe the post-44th Amendment position on Article 352, which tightened the grounds and procedural safeguards for declaring a National Emergency (a response to the perceived misuse of Emergency powers in 1975–77)."}},{"content_key":"competitive-s4-q5","active_date":"2026-10-11","tag":"General Knowledge","q":"Consider the following statements on fiscal terms used in the Union Budget:\n1. Fiscal deficit is the excess of total expenditure over total receipts excluding borrowings.\n2. Revenue deficit occurs when revenue expenditure exceeds revenue receipts.\n3. Primary deficit equals the fiscal deficit minus interest payments.\nWhich of the statements given above is/are correct?","opts":["1 and 2 only","2 and 3 only","1 and 3 only","1, 2 and 3"],"correct":3,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":100,"title":"General Knowledge · 5","grade":"Competitive","kind":"mcq","hint":"Check each statement independently before combining your choices.","answer":"all three are standard, correct definitions used in Indian public finance."}},{"content_key":"competitive-s4-q6","active_date":"2026-10-12","tag":"General Knowledge","q":"Consider the following statements about the Government of India Act, 1935:\n1. It introduced provincial autonomy for the first time.\n2. It provided for an All-India Federation, which never actually came into being.\n3. It abolished dyarchy at the provincial level while introducing a form of dyarchy at the Centre.\nWhich of the statements given above is/are correct?","opts":["1 and 2 only","2 and 3 only","1 and 3 only","1, 2 and 3"],"correct":3,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":101,"title":"General Knowledge · 6","grade":"Competitive","kind":"mcq","hint":"Check each statement independently before combining your choices.","answer":"the 1935 Act ended provincial dyarchy (replacing it with provincial autonomy) but introduced dyarchy for the first time at the central/federal level for certain subjects; the proposed federation never materialised as too few princely states acceded."}},{"content_key":"competitive-s4-q7","active_date":"2026-10-13","tag":"General Knowledge","q":"Consider the following statements:\n1. Diamond and graphite are both allotropes of carbon, but graphite conducts electricity while diamond does not, owing to differences in bonding.\n2. In graphite, each carbon atom is covalently bonded to three others, leaving one delocalised electron per atom that permits conduction.\n3. Diamond is denser than graphite because of its three-dimensional tetrahedral bonding.\nWhich of the statements given above is/are correct?","opts":["1 and 2 only","2 and 3 only","1 and 3 only","1, 2 and 3"],"correct":3,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":102,"title":"General Knowledge · 7","grade":"Competitive","kind":"mcq","hint":"Check each statement independently before combining your choices.","answer":"all three statements correctly describe the structural basis for the differing physical properties of these two carbon allotropes."}},{"content_key":"competitive-s4-q8","active_date":"2026-10-14","tag":"General Knowledge","q":"Consider the following statements regarding the Supreme Court of India:\n1. A Supreme Court judge can be removed only by a Presidential order following an address by each House of Parliament, supported by a special majority.\n2. The Supreme Court has original, appellate, and advisory jurisdiction.\n3. The right to move the Supreme Court under Article 32 for enforcement of Fundamental Rights can never be suspended, even during a National Emergency.\nWhich of the statements given above is/are correct?","opts":["1 and 2 only","2 and 3 only","1 and 3 only","1, 2 and 3"],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":103,"title":"General Knowledge · 8","grade":"Competitive","kind":"mcq","hint":"Check each statement independently before combining your choices.","answer":"Statement 3 is incorrect: under Article 359, the President may suspend the right to move courts for the enforcement of most Fundamental Rights during a National Emergency; only Articles 20 and 21 are explicitly protected from such suspension."}},{"content_key":"competitive-s4-q9","active_date":"2026-10-15","tag":"General Knowledge","q":"Consider the following statements about the Indian monsoon:\n1. The southwest monsoon contributes roughly 70–80% of India's total annual rainfall.\n2. The Tamil Nadu coast receives most of its rainfall from the northeast (retreating) monsoon rather than the southwest monsoon.\n3. A 'break' in the monsoon refers to a prolonged dry spell during the rainy season, often linked to a shift in the monsoon trough.\nWhich of the statements given above is/are correct?","opts":["1 and 2 only","2 and 3 only","1 and 3 only","1, 2 and 3"],"correct":3,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":104,"title":"General Knowledge · 9","grade":"Competitive","kind":"mcq","hint":"Check each statement independently before combining your choices.","answer":"all three are accurate and commonly tested facts about the Indian monsoon system."}},{"content_key":"competitive-s4-q10","active_date":"2026-10-16","tag":"General Knowledge","q":"Consider the following statements on monetary policy tools used by the RBI:\n1. Statutory Liquidity Ratio (SLR) is the percentage of a bank's net demand and time liabilities that must be kept as liquid assets WITH THE RBI.\n2. Cash Reserve Ratio (CRR) requires banks to keep a percentage of deposits as reserves with the RBI, on which no interest is earned.\n3. An increase in the Repo Rate makes borrowing costlier for commercial banks, typically leading to higher lending rates for consumers.\nWhich of the statements given above is/are correct?","opts":["1 and 2 only","2 and 3 only","1 and 3 only","1, 2 and 3"],"correct":1,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":105,"title":"General Knowledge · 10","grade":"Competitive","kind":"mcq","hint":"Check each statement independently before combining your choices.","answer":"Statement 1 is incorrect: unlike CRR, the SLR is maintained by banks THEMSELVES (as cash, gold, or approved government securities), not deposited with the RBI. This distinction is a frequently tested point."}},{"content_key":"competitive-s4-q11","active_date":"2026-10-17","tag":"General Knowledge","q":"Consider the following statements:\n1. The Indian National Congress was founded in 1885 by Allan Octavian Hume, a retired British civil servant.\n2. The Muslim League was founded in 1906 in Dhaka.\n3. The Ghadar Party was founded in the United States in 1913, mainly by Indian immigrants, aiming to overthrow British rule through armed revolution.\nWhich of the statements given above is/are correct?","opts":["1 and 2 only","2 and 3 only","1 and 3 only","1, 2 and 3"],"correct":3,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":106,"title":"General Knowledge · 11","grade":"Competitive","kind":"mcq","hint":"Check each statement independently before combining your choices.","answer":"all three statements are well-established facts of the Indian nationalist movement."}},{"content_key":"competitive-s4-q12","active_date":"2026-10-18","tag":"General Knowledge","q":"Consider the following statements regarding the 73rd Constitutional Amendment Act, 1992:\n1. It gave constitutional status to Panchayati Raj Institutions by adding Part IX to the Constitution.\n2. It mandates reservation of not less than one-third of total seats for women in Panchayats.\n3. It mandates a uniform three-tier structure of Panchayats in every state, regardless of population.\nWhich of the statements given above is/are correct?","opts":["1 and 2 only","2 and 3 only","1 and 3 only","1, 2 and 3"],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":107,"title":"General Knowledge · 12","grade":"Competitive","kind":"mcq","hint":"Check each statement independently before combining your choices.","answer":"Statement 3 is incorrect: states with a population below 20 lakh MAY choose not to have the intermediate (middle) tier of Panchayats, so a uniform three-tier structure is not mandatory everywhere."}},{"content_key":"competitive-s4-q13","active_date":"2026-10-19","tag":"General Knowledge","q":"Consider the following statements:\n1. A body's weight is identical at the equator and at the poles because its mass does not change.\n2. Astronauts in an orbiting spacecraft experience weightlessness because there is no gravity in space.\n3. The acceleration due to gravity (g) is slightly greater at the poles than at the equator, due to Earth's oblate shape and its rotation.\nWhich of the statements given above is/are correct?","opts":["1 only","2 only","3 only","1 and 3 only"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":108,"title":"General Knowledge · 13","grade":"Competitive","kind":"mcq","hint":"Check each statement independently before combining your choices.","answer":"Statement 1 confuses mass with weight (weight = mass × g, and g varies with location, so weight is NOT identical everywhere). Statement 2 is a common misconception: gravity is still substantial at orbital altitude; weightlessness results from continuous free-fall while in orbit, not the absence of gravity."}},{"content_key":"competitive-s4-q14","active_date":"2026-10-20","tag":"General Knowledge","q":"Consider the following statements about Indian soils:\n1. Black (regur) soil, ideal for cotton cultivation, forms from the weathering of Deccan trap (basaltic) rocks.\n2. Laterite soil forms due to intense leaching under high temperature and heavy rainfall, and is typically poor in nitrogen and phosphorus.\n3. Alluvial soil of the Indo-Gangetic plains is generally deficient in nitrogen but rich in potash and lime.\nWhich of the statements given above is/are correct?","opts":["1 and 2 only","2 and 3 only","1 and 3 only","1, 2 and 3"],"correct":3,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":109,"title":"General Knowledge · 14","grade":"Competitive","kind":"mcq","hint":"Check each statement independently before combining your choices.","answer":"all three statements correctly describe the formation and characteristics of these major Indian soil types."}},{"content_key":"competitive-s4-q15","active_date":"2026-10-21","tag":"General Knowledge","q":"Consider the following statements:\n1. A Money Bill can be introduced only in the Lok Sabha, not the Rajya Sabha.\n2. The Rajya Sabha can amend or reject a Money Bill, though its changes are not binding on the Lok Sabha.\n3. If the Speaker of the Lok Sabha certifies a Bill as a Money Bill, that certification is final and ordinarily cannot be questioned in a court of law.\nWhich of the statements given above is/are correct?","opts":["1 and 2 only","2 and 3 only","1 and 3 only","1, 2 and 3"],"correct":2,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":110,"title":"General Knowledge · 15","grade":"Competitive","kind":"mcq","hint":"Check each statement independently before combining your choices.","answer":"Statement 2 is incorrect: the Rajya Sabha cannot amend or reject a Money Bill; it may only make recommendations within 14 days, which the Lok Sabha is free to accept or reject entirely."}},{"content_key":"competitive-s4-q16","active_date":"2026-10-22","tag":"General Knowledge","q":"Consider the following statements:\n1. Cost-push inflation occurs when rising production costs (such as wages or raw materials) lead producers to raise prices.\n2. Demand-pull inflation occurs when aggregate demand in the economy outpaces aggregate supply.\n3. Stagflation refers to a situation of simultaneous high inflation and high economic growth.\nWhich of the statements given above is/are correct?","opts":["1 and 2 only","2 and 3 only","1 and 3 only","1, 2 and 3"],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":111,"title":"General Knowledge · 16","grade":"Competitive","kind":"mcq","hint":"Check each statement independently before combining your choices.","answer":"Statement 3 is incorrect: stagflation refers to high inflation combined with high UNEMPLOYMENT and stagnant (low or negative) growth, not high growth — this combination is what makes it a policy paradox."}},{"content_key":"competitive-s4-q17","active_date":"2026-10-23","tag":"General Knowledge","q":"Consider the following statements about the Constituent Assembly of India:\n1. It was constituted under the Cabinet Mission Plan of 1946.\n2. Dr. Rajendra Prasad was its President, while Dr. B. R. Ambedkar chaired the Drafting Committee.\n3. It took exactly two years to complete the drafting and adoption of the Constitution.\nWhich of the statements given above is/are correct?","opts":["1 and 2 only","2 and 3 only","1 and 3 only","1, 2 and 3"],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":112,"title":"General Knowledge · 17","grade":"Competitive","kind":"mcq","hint":"Check each statement independently before combining your choices.","answer":"Statement 3 is incorrect: the Assembly took 2 years, 11 months, and 18 days (first meeting 9 December 1946; Constitution adopted 26 November 1949), not exactly two years."}},{"content_key":"competitive-s4-q18","active_date":"2026-10-24","tag":"General Knowledge","q":"Consider the following statements:\n1. The Karakoram Pass connects Ladakh with Xinjiang, China.\n2. The Nathu La and Jelep La passes connect Sikkim with the Tibet Autonomous Region of China.\n3. The Radcliffe Line demarcates the boundary between India and Myanmar.\nWhich of the statements given above is/are correct?","opts":["1 and 2 only","2 and 3 only","1 and 3 only","1, 2 and 3"],"correct":0,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":113,"title":"General Knowledge · 18","grade":"Competitive","kind":"mcq","hint":"Check each statement independently before combining your choices.","answer":"Statement 3 is incorrect: the Radcliffe Line demarcated the India-Pakistan (and India-East Pakistan/Bangladesh) boundary in 1947; the India-Myanmar boundary was demarcated separately."}},{"content_key":"competitive-s4-q19","active_date":"2026-10-25","tag":"General Knowledge","q":"Consider the following statements regarding amendment of the Indian Constitution under Article 368:\n1. Some provisions can be amended by a simple parliamentary majority, without invoking the special Article 368 procedure.\n2. Amendments affecting the federal structure require ratification by at least half of the State Legislatures, in addition to a special majority in Parliament.\n3. The 'basic structure' doctrine, limiting Parliament's amending power, was laid down in the Kesavananda Bharati case (1973).\nWhich of the statements given above is/are correct?","opts":["1 and 2 only","2 and 3 only","1 and 3 only","1, 2 and 3"],"correct":3,"sort_order":0,"published":true,"class_level":null,"metadata":{"number":114,"title":"General Knowledge · 19","grade":"Competitive","kind":"mcq","hint":"Check each statement independently before combining your choices.","answer":"all three statements correctly describe India's three-tier constitutional amendment procedure and the basic structure doctrine."}}]$puzzles$::jsonb) AS row_data(
    content_key text,
    active_date date,
    tag text,
    q text,
    opts jsonb,
    correct integer,
    sort_order integer,
    published boolean,
    class_level text,
    metadata jsonb
  )
)
INSERT INTO public.edubite_content_questions (
  domain,
  content_key,
  active_date,
  tag,
  q,
  opts,
  correct,
  sort_order,
  published,
  class_level,
  metadata,
  updated_at
)
SELECT
  'puzzle',
  content_key,
  active_date,
  tag,
  q,
  opts,
  correct,
  sort_order,
  published,
  class_level,
  metadata,
  now()
FROM source
ON CONFLICT (domain, content_key) WHERE domain = 'puzzle'
DO UPDATE SET
  active_date = EXCLUDED.active_date,
  tag = EXCLUDED.tag,
  q = EXCLUDED.q,
  opts = EXCLUDED.opts,
  correct = EXCLUDED.correct,
  sort_order = EXCLUDED.sort_order,
  published = EXCLUDED.published,
  class_level = EXCLUDED.class_level,
  metadata = EXCLUDED.metadata,
  updated_at = now();

COMMENT ON COLUMN public.edubite_content_questions.content_key IS
  'Stable source identifier for unified content; required for puzzle rows.';
COMMENT ON COLUMN public.edubite_content_questions.metadata IS
  'Domain-specific metadata. Puzzle rows contain title, grade, kind, hint, answer, and number.';
